const raw = ($json.data || "").trim();

const esc = (s) => s
  .replace(/&/g, "&amp;")
  .replace(/</g, "&lt;")
  .replace(/>/g, "&gt;");

const mdBold = (s) => s.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");

const lines = raw.split("\n").map(l => l.trim());

// Helpers para encontrar secciones
function sectionBetween(startHeader, endHeader) {
  const start = lines.findIndex(l => l.startsWith(startHeader));
  if (start === -1) return [];
  const end = endHeader
    ? lines.findIndex((l, i) => i > start && l.startsWith(endHeader))
    : -1;
  return lines.slice(start + 1, end === -1 ? lines.length : end);
}

// Extrae resumen (líneas con "- ...")
const resumen = sectionBetween("## Resumen", "## Trades");
const trades = sectionBetween("## Trades", "## Posiciones");
const posiciones = sectionBetween("## Posiciones", "## Alertas");
const alertas = sectionBetween("## Alertas", "## Parámetros");
const params = sectionBetween("## Parámetros", null);

// Parse resumen clave-valor
const resumenKV = resumen
  .filter(l => l.startsWith("- "))
  .map(l => l.slice(2))
  .map(l => {
    const idx = l.indexOf(":");
    if (idx === -1) return null;
    return { k: l.slice(0, idx).trim(), v: l.slice(idx + 1).trim() };
  })
  .filter(Boolean);

// Parse posiciones a tabla
// Formato esperado: - **TICKER**: X sh | avg Y | close Z | mv A | pnl B
const posRows = posiciones
  .filter(l => l.startsWith("- "))
  .map(l => l.slice(2))
  .map(l => {
    const m = l.match(/^\*\*(.+?)\*\*:\s*([0-9.]+)\s*sh\s*\|\s*avg\s*([0-9.]+)\s*\|\s*close\s*([0-9.]+)\s*\|\s*mv\s*([0-9.]+)\s*\|\s*pnl\s*([-\d.]+%)/i);
    if (!m) return null;
    return {
      ticker: m[1],
      sh: m[2],
      avg: m[3],
      close: m[4],
      mv: m[5],
      pnl: m[6],
    };
  })
  .filter(Boolean);

const resumenCards = resumenKV.map(({k,v}) => `
  <div style="border:1px solid #e5e7eb;border-radius:12px;padding:10px;background:#ffffff;">
    <div style="font-size:12px;color:#6b7280;margin-bottom:4px;">${esc(k)}</div>
    <div style="font-size:16px;font-weight:800;color:#111827;">${mdBold(esc(v))}</div>
  </div>
`).join("");

const posTable = posRows.length ? `
  <table style="width:100%;border-collapse:separate;border-spacing:0;overflow:hidden;border:1px solid #e5e7eb;border-radius:14px;background:#ffffff;">
    <thead>
      <tr>
        <th style="text-align:left;padding:10px;border-bottom:1px solid #e5e7eb;background:#f9fafb;">Ticker</th>
        <th style="text-align:right;padding:10px;border-bottom:1px solid #e5e7eb;background:#f9fafb;">Shares</th>
        <th style="text-align:right;padding:10px;border-bottom:1px solid #e5e7eb;background:#f9fafb;">Avg</th>
        <th style="text-align:right;padding:10px;border-bottom:1px solid #e5e7eb;background:#f9fafb;">Close</th>
        <th style="text-align:right;padding:10px;border-bottom:1px solid #e5e7eb;background:#f9fafb;">MV</th>
