          <td style="padding:10px;border-bottom:1px solid #f1f5f9;text-align:right;">${esc(r.mv)}</td>
          <td style="padding:10px;border-bottom:1px solid #f1f5f9;text-align:right;">${esc(r.pnl)}</td>
