// helpers
const pick = (re) => {
  const m = raw.match(re);
  return m ? m[1] : null;
};
const num = (s) => (s == null ? null : Number(String(s).replace(/,/g, "")));

const snapshot = {
  ts: new Date().toISOString(),
  slot: "CLOSE",

  equityPre: num(pick(/Equity \(pre\): \*\*([0-9.]+)\*\*/)),
  equityPost: num(pick(/Equity \(post\): \*\*([0-9.]+)\*\*/)),
  cash: num(pick(/Cash: \*\*([0-9.]+)\*\*/)),
  exposurePct: num(pick(/Exposición: \*\*([-0-9.]+)%\*\*/)),
  drawdownPct: num(pick(/Drawdown \(vs pico\): \*\*([-0-9.]+)%\*\*/)),
  targetPerPos: num(pick(/Target por posición .*?: \*\*([0-9.]+)\*\*/)),
  rawLen: raw.length
};

return [{ json: { ...$json, snapshot } }];
